impl Solution { pub fn find_high_access_employees(black_a: Vec<Vec<String>>) -> Vec<String> { let mut black_m = std::collections::HashMap::new(); for black_e in black_a { black_m.entry(black_e[0].clone()).or_insert(vec![]).push(black_e[1][..2].parse::<i32>().unwrap() * 60 + black_e[1][2..].parse::<i32>().unwrap()); } black_m.into_iter().map(|(n, mut t)| { t.sort_unstable(); (n, t) }).filter(|(_, t)| t.windows(3).any(|w| w[2] - w[0] < 60)).map(|(n, _)| n).collect() } }